const META_TOKEN = 'TU_TOKEN_MAESTRO_DE_META_AQUI';

const rawTarget = $('Webhook POST').item.json.body.display_phone_number || '';
const targetPhone = rawTarget.replace(/\D/g, '');
const userId = $('Validar Usuario (Supabase)').item.json.id || '';

if (!targetPhone) {
  return [{ json: { found: false, error: 'No se proporcionó un teléfono válido.' } }];
}

try {
  const wabaRes = await fetch('https://graph.facebook.com/v20.0/me/whatsapp_business_accounts', {
    headers: { 'Authorization': `Bearer ${META_TOKEN}` }
  });
  const wabaData = await wabaRes.json();
  const wabas = wabaData.data || [];

  let matched = null;

  for (const waba of wabas) {
    const phoneRes = await fetch(`https://graph.facebook.com/v20.0/${waba.id}/phone_numbers`, {
      headers: { 'Authorization': `Bearer ${META_TOKEN}` }
    });
    const phoneData = await phoneRes.json();
    const phoneNumbers = phoneData.data || [];

    for (const phone of phoneNumbers) {
      if (!phone.display_phone_number) continue;
      const cleanDisplay = phone.display_phone_number.replace(/\D/g, '');

      if (cleanDisplay.endsWith(targetPhone) || targetPhone.endsWith(cleanDisplay)) {
        matched = {
          user_id: userId,
          phone_number_id: phone.id,
          waba_id: waba.id,
          display_phone_number: phone.display_phone_number,
          active: true
        };
        break;
      }
    }
    if (matched) break;
  }

  return [{ json: matched ? { found: true, ...matched } : { found: false } }];
} catch (error) {
  return [{ json: { found: false, error: error.message } }];
}

